/**
 * Widget Tests
 */
test.describe('Functional Tests — Widgets', () => {
  test('Global Search widget has search functionality', async ({ page }) => {
    await page.goto('/admin/widgets/global-search.html', { waitUntil: 'domcontentloaded', timeout: 15000 });

    const content = await page.content();
    // Check for search-related elements
    expect(content).toMatch(/search|find|lookup|tìm kiếm/i);

    // Check for search input
    const searchInput = page.locator('input[type="search"], input[placeholder*="search" i], [class*="search"]');
    await expect(searchInput.first()).toBeVisible({ timeout: 5000 }).catch(() => {});
  });

  test('Notification Bell widget has notification elements', async ({ page }) => {
    await page.goto('/admin/widgets/notification-bell.html', { waitUntil: 'domcontentloaded', timeout: 15000 });

    const content = await page.content();
    // Check for notification-related content
    expect(content).toMatch(/notification|alert|bell|thông báo/i);

    // Check for bell icon or notification list
    const bellIcon = page.locator('[class*="bell"], [class*="notification"], svg[aria-label*="notification" i]');
    await expect(bellIcon.first()).toBeVisible({ timeout: 5000 }).catch(() => {});
  });

  test('Theme Toggle widget has theme switching', async ({ page }) => {
    await page.goto('/admin/widgets/theme-toggle.html', { waitUntil: 'domcontentloaded', timeout: 15000 });

    const content = await page.content();
    // Check for theme-related content
    expect(content).toMatch(/theme|dark|light|mode|toggle/i);

    // Check for theme toggle button
    const toggleBtn = page.locator('[class*="theme"], [class*="toggle"], [class*="dark"], [class*="light"], button[aria-label*="theme" i]');
    await expect(toggleBtn.first()).toBeVisible({ timeout: 5000 }).catch(() => {});
  });
});

/**
 * Accessibility Tests — Demo Pages
 */
test.describe('Accessibility Tests — Demo Pages', () => {
  test('Components Demo has proper heading hierarchy', async ({ page }) => {
    await page.goto('/admin/components-demo.html', { waitUntil: 'domcontentloaded', timeout: 15000 });

    // Check for h1
    const h1Count = await page.locator('h1').count();
    expect(h1Count).toBeLessThanOrEqual(1);

    // Check for lang attribute
    const lang = await page.getAttribute('html', 'lang');
    expect(lang).toBeTruthy();
  });

  test('UI Components Demo has proper heading hierarchy', async ({ page }) => {
    await page.goto('/admin/ui-components-demo.html', { waitUntil: 'domcontentloaded', timeout: 15000 });

    const h1Count = await page.locator('h1').count();
    expect(h1Count).toBeLessThanOrEqual(1);

    const lang = await page.getAttribute('html', 'lang');
    expect(lang).toBeTruthy();
  });
});

/**
 * Responsive Tests — Demo Pages
 */
test.describe('Responsive Tests — Demo Pages', () => {
  const VIEWPORTS = [
    { name: 'Mobile (375px)', width: 375, height: 667 },
    { name: 'Tablet (768px)', width: 768, height: 1024 },
    { name: 'Desktop (1024px)', width: 1024, height: 768 },
  ];

  for (const viewport of VIEWPORTS) {
    test(`Components Demo renders on ${viewport.name}`, async ({ page }) => {
      await page.setViewportSize({ width: viewport.width, height: viewport.height });
      await page.goto('/admin/components-demo.html', { waitUntil: 'domcontentloaded', timeout: 15000 });

      // Check page loads without errors
      const content = await page.content();
      expect(content.length).toBeGreaterThan(100);
    });

    test(`Global Search renders on ${viewport.name}`, async ({ page }) => {
      await page.setViewportSize({ width: viewport.width, height: viewport.height });
      await page.goto('/admin/widgets/global-search.html', { waitUntil: 'domcontentloaded', timeout: 15000 });

      const content = await page.content();
      expect(content.length).toBeGreaterThan(100);
    });
  }
});
